import{_ as t,o as a,c as s,a2 as o}from"./chunks/framework.C69UpXSI.js";const u=JSON.parse('{"title":"Commands","description":"","frontmatter":{},"headers":[],"relativePath":"en/usage/commands.md","filePath":"en/usage/commands.md"}'),n={name:"en/usage/commands.md"};function i(d,e,c,r,l,p){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="commands" tabindex="-1">Commands <a class="header-anchor" href="#commands" aria-label="Permalink to &quot;Commands&quot;">​</a></h1><p>TurboDev slash commands.</p><p>All commands start with <code>/</code>. Type <code>/</code> in the input bar to see available commands.</p><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>/help</code></td><td>Show available commands</td></tr><tr><td><code>/init</code></td><td>Create or update <code>AGENTS.md</code></td></tr><tr><td><code>/model</code></td><td>Open model selector</td></tr><tr><td><code>/agent</code></td><td>Open agent selector</td></tr><tr><td><code>/setup</code></td><td>Re-run setup wizard</td></tr><tr><td><code>/clear</code></td><td>Clear chat history</td></tr><tr><td><code>/compact</code></td><td>Compact the conversation to free context window</td></tr><tr><td><code>/new</code></td><td>Start a new session</td></tr><tr><td><code>/sessions</code></td><td>List and switch between sessions</td></tr><tr><td><code>/exit</code></td><td>Exit TurboDev</td></tr></tbody></table><h2 id="init" tabindex="-1">/init <a class="header-anchor" href="#init" aria-label="Permalink to &quot;/init&quot;">​</a></h2><p>Creates or updates <code>AGENTS.md</code> in your project.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/init</span></span></code></pre></div><p>If <code>AGENTS.md</code> already exists, you can choose to:</p><ol><li><strong>Overwrite</strong> — Start fresh</li><li><strong>Append</strong> — Add new sections to existing file</li></ol><p>The wizard detects your project type and generates relevant sections.</p><h2 id="model" tabindex="-1">/model <a class="header-anchor" href="#model" aria-label="Permalink to &quot;/model&quot;">​</a></h2><p>Opens an interactive model selector.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/model</span></span></code></pre></div><p>Navigate with <code>↑</code>/<code>↓</code> or <code>j</code>/<code>k</code>, select with a number (1–9), cancel with <code>Esc</code> or <code>q</code>. If there are more than 9 models, pages are available.</p><h2 id="agent" tabindex="-1">/agent <a class="header-anchor" href="#agent" aria-label="Permalink to &quot;/agent&quot;">​</a></h2><p>Opens the agent selector.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/agent</span></span></code></pre></div><p>Type the agent&#39;s number to select it, press <code>Esc</code> to cancel. Shows all available primary agents with their descriptions.</p><h2 id="setup" tabindex="-1">/setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;/setup&quot;">​</a></h2><p>Re-runs the initial setup wizard to change your API key or model.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/setup</span></span></code></pre></div><h2 id="clear" tabindex="-1">/clear <a class="header-anchor" href="#clear" aria-label="Permalink to &quot;/clear&quot;">​</a></h2><p>Clears the entire chat history and conversation context.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/clear</span></span></code></pre></div><h2 id="compact" tabindex="-1">/compact <a class="header-anchor" href="#compact" aria-label="Permalink to &quot;/compact&quot;">​</a></h2><p>Compacts the conversation by summarizing it via AI. This frees up space in the context window, allowing longer sessions without losing the conversation&#39;s key points.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/compact</span></span></code></pre></div><p>Auto-compaction triggers at <strong>85%</strong> of the context window. You&#39;ll be notified at <strong>75%</strong>. Use <code>/compact</code> manually at any time.</p><h2 id="new" tabindex="-1">/new <a class="header-anchor" href="#new" aria-label="Permalink to &quot;/new&quot;">​</a></h2><p>Starts a new empty session. The current session is saved automatically and can be resumed later with <code>/sessions</code>.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/new</span></span></code></pre></div><h2 id="sessions" tabindex="-1">/sessions <a class="header-anchor" href="#sessions" aria-label="Permalink to &quot;/sessions&quot;">​</a></h2><p>Lists all saved sessions sorted by most recent. Select a session by number to restore it.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/sessions</span></span></code></pre></div><p>Shows each session with its title, relative time, and message count. Press <code>Esc</code> to cancel.</p><h2 id="exit" tabindex="-1">/exit <a class="header-anchor" href="#exit" aria-label="Permalink to &quot;/exit&quot;">​</a></h2><p>Exits TurboDev.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/exit</span></span></code></pre></div>',39)])])}const m=t(n,[["render",i]]);export{u as __pageData,m as default};
